SELECT p.id, p.title, p.price, p.condition_level AS conditionLevel, p.view_count AS viewCount, p.favorite_count AS favoriteCount, p.create_time AS createTime, p.images AS coverImage, ca.name AS campusName, u.id AS sellerId, u.nick_name AS sellerNickName, u.avatar_url AS sellerAvatarUrl FROM product p LEFT JOIN campus ca ON p.campus_id = ca.id LEFT JOIN user u ON p.user_id = u.id WHERE p.status = 1 AND p.is_deleted = 0
AND p.campus_id = #{campusId}
AND p.category_id = #{categoryId}
AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR p.description LIKE CONCAT('%', #{keyword}, '%'))
AND p.price >= #{minPrice}
AND p.price <= #{maxPrice}
ORDER BY p.price ASC, p.create_time DESC
ORDER BY p.price DESC, p.create_time DESC
ORDER BY p.create_time DESC

SELECT p.id, p.title, p.price, p.condition_level AS conditionLevel, p.view_count AS viewCount, p.favorite_count AS favoriteCount, p.create_time AS createTime, p.images AS coverImage, ca.name AS campusName, u.id AS sellerId, u.nick_name AS sellerNickName, u.avatar_url AS sellerAvatarUrl FROM product p LEFT JOIN campus ca ON p.campus_id = ca.id LEFT JOIN user u ON p.user_id = u.id WHERE p.user_id = #{userId} AND p.is_deleted = 0
AND p.status = #{status}
ORDER BY p.create_time DESC
